mapper.select:
SELECT p.*, c.course_name AS courseName, m.major_name AS majorName
FROM sys_exam_plan p
LEFT JOIN sys_course c ON c.id = p.course_id
LEFT JOIN sys_major  m ON m.id = p.major_id
WHERE p.deleted = 0

    AND p.exam_year = #{q.examYear}


    AND p.exam_term = #{q.examTerm}


    AND p.status = #{q.status}


    AND p.major_id = #{q.majorId}


    AND (p.plan_code LIKE '%' || #{q.keyword} || '%' OR p.plan_name LIKE '%' || #{q.keyword} || '%')

ORDER BY p.id DESC

SELECT p.*, c.course_name AS courseName, m.major_name AS majorName FROM sys_exam_plan p LEFT JOIN sys_course c ON c.id = p.course_id LEFT JOIN sys_major m ON m.id = p.major_id WHERE p.deleted = 0 AND p.status = 'PUBLISHED'
AND p.exam_year = #{q.examYear}
AND p.exam_term = #{q.examTerm}
AND (p.major_id IS NULL OR p.major_id = #{q.majorId})
AND (p.plan_name LIKE '%' || #{q.keyword} || '%' OR c.course_name LIKE '%' || #{q.keyword} || '%')
ORDER BY p.exam_date ASC
